-- HaynesPro chassis crawl → catalog ingest
-- Source crawl: scrapers/output/haynespro-crawl-vw-tiguan-ii-ad-2026-05-23.json
-- HaynesPro modelId: d_317000050 (Tiguan II (AD, AX, BT, BW, BJ))
-- Crawl fetched_at: 2026-05-23T09:14:02.852Z
-- Target catalog generation_id: 44
-- Engines: CZEA, CZCA, CZDA, DJVA, CZDB, DADA, DACA, DACB, DPCA, DPBE, DXDB, DGDB, DFHA, DFGA, DFGC, CRGB, DBGA, DBGC, CRFD, CYKC, DTUA, DTSA, DTSB, DTRC, CUAA, CZPA, CHHB, DGUA, DGVA, CXDA, DKTA, DNJA, DKZA, DNLA, DNPA, DNNA, DTEA, DNFG, DSFE
-- Generated by scrapers/haynespro/ingest_to_sql.ts on 2026-05-23T09:33:47.758Z

SET NAMES utf8mb4;

-- 1. HaynesPro source row (is_public=0, citation only for audit trail)
SET @s_haynes := (SELECT id FROM sources WHERE url = 'https://www.workshopdata.com/touch/site/layout/modelTypesList?modelId=d_317000050' ORDER BY id DESC LIMIT 1);

-- 2. Engines — auto-insert any not yet in catalog

-- 3. fluid_specs — engine_oil + coolant scoped to gen_id 44
SET @gen := 44;


-- 4. spec_sources — link inserted fluid_specs rows to the HaynesPro source
SELECT 'fluid_specs', fs.id, @s_haynes
FROM fluid_specs fs
JOIN engines e ON e.id = fs.engine_id
WHERE fs.generation_id = @gen
  AND e.code IN ('CZEA', 'CZCA', 'CZDA', 'DJVA', 'CZDB', 'DADA', 'DACA', 'DACB', 'DPCA', 'DPBE', 'DXDB', 'DGDB', 'DFHA', 'DFGA', 'DFGC', 'CRGB', 'DBGA', 'DBGC', 'CRFD', 'CYKC', 'DTUA', 'DTSA', 'DTSB', 'DTRC', 'CUAA', 'CZPA', 'CHHB', 'DGUA', 'DGVA', 'CXDA', 'DKTA', 'DNJA', 'DKZA', 'DNLA', 'DNPA', 'DNNA', 'DTEA', 'DNFG', 'DSFE')
  AND fs.fluid_type IN ('engine_oil', 'coolant');

-- 5. Audit
SELECT e.code, COUNT(fs.id) AS rows_count,
       GROUP_CONCAT(DISTINCT CONCAT(fs.fluid_type, ' ', fs.capacity_l, 'L ', COALESCE(fs.viscosity,''), ' ', COALESCE(fs.spec_standard,'')) SEPARATOR ' | ') AS specs
FROM fluid_specs fs
JOIN engines e ON e.id = fs.engine_id
WHERE fs.generation_id = @gen
  AND e.code IN ('CZEA', 'CZCA', 'CZDA', 'DJVA', 'CZDB', 'DADA', 'DACA', 'DACB', 'DPCA', 'DPBE', 'DXDB', 'DGDB', 'DFHA', 'DFGA', 'DFGC', 'CRGB', 'DBGA', 'DBGC', 'CRFD', 'CYKC', 'DTUA', 'DTSA', 'DTSB', 'DTRC', 'CUAA', 'CZPA', 'CHHB', 'DGUA', 'DGVA', 'CXDA', 'DKTA', 'DNJA', 'DKZA', 'DNLA', 'DNPA', 'DNNA', 'DTEA', 'DNFG', 'DSFE')
GROUP BY e.code ORDER BY e.code;
